import React, { useEffect, useState } from "react";
import { useParams, useHistory } from "react-router-dom";
import { Button, Col, Row } from "react-bootstrap";
import ViewCard from "./ViewCard";
import { listCards } from "../../utils/api/index.js";
import { Trash, Book } from "react-bootstrap-icons";

function DeckView({ decks, handleDeleteDeck }) {
  const history = useHistory();
  const [cards, setCards] = useState([]);
  const params = useParams();
  const deck = decks.find((item) => item.id.toString() === params.deckId);

  useEffect(() => {
    async function loadCards() {
      const cardData = await listCards(deck.id);
      setCards(cardData);
    }
    loadCards();
  }, []);

  const listOfCards = cards.map((card) => {
    return <ViewCard card={card} />;
  });

  if (!deck) return <p>loading...</p>;
  return (
    <div>
      <h2>{deck.name}</h2>
      <p>{deck.description}</p>
      <Row>
        <Col>
          <Button className="m-1" variant="secondary">
            Edit
          </Button>
          <Button className="m-1">
            <Book />
            Study
          </Button>
          <Button className="m-1">Add Cards</Button>
        </Col>
        <Col className="col-1">
          <Button
            onClick={() => {
              if (
                window.confirm(
                  "You sure you want to delete that dawg? You won't get it back"
                )
              ) {
                handleDeleteDeck(deck.id);
                history.push("/");
              }
            }}
            className="m-1 text-right"
            variant="danger"
          >
            <Trash />
          </Button>
        </Col>
      </Row>
      <h1>Cards</h1>
      {listOfCards}
    </div>
  );
}

export default DeckView;
